		got, err := s.Get(testCtx(), b.ID)
		require.NoError(t, err)
		assert.Equal(t, StatusClosed, got.Status)
		events, err = s.Events(b.ID)
		require.NoError(t, err)
		assert.Len(t, events, 3)
	})
