}

func newAxonStoreWithTransport(t *testing.T) (*Store, *fakeAxonGraphQLTransport) {
	t.Helper()
	dir := filepath.Join(t.TempDir(), ddxroot.DirName)
	transport := newFakeAxonGraphQLTransport()
	s := NewStore(dir)
